const compiledFilesTransformer: OutputTransformer = (
  output,
  _services,
  _config,
) => {
  let modifiedContent = addJsExtensionsIfNeeded(output);

  // Fixes the import of types from the ethers plugin. Update the imports from "ethers-v2" to "ethers-v3"
  modifiedContent = modifiedContent.replaceAll(
    'from "@nomicfoundation/hardhat-ethers/types"',
    'from "@nomicfoundation/hardhat-ethers/types"',
  );

  // Fixes the module augmentation to use the types declared in "ethers-v3"
  modifiedContent = modifiedContent.replaceAll(
    'declare module "hardhat/types/runtime"',
    'declare module "@nomicfoundation/hardhat-ethers/types"',
  );

  modifiedContent = addSupportForAttachMethod(modifiedContent);

  return modifiedContent;
};

try {
  await fsPromises.copyFile(source, destination);
} catch (e) {
  ensureNodeErrnoExceptionError(e);
  if (e.code === "ENOENT") {
    if (!(await exists(source))) {
      throw new FileNotFoundError(source, e);
    }
    if (!(await exists(destination))) {
      throw new FileNotFoundError(destination, e);
    }
  }

  // On linux, trying to copy a directory will throw EISDIR,
  // on Windows it will throw EPERM, and on macOS it will throw ENOTSUP.
  if (e.code === "EISDIR" || e.code === "EPERM" || e.code === "ENOTSUP") {
    if (await isDirectory(source)) {
      throw new IsDirectoryError(source, e);
    }
    if (await isDirectory(destination)) {
      throw new IsDirectoryError(destination, e);
    }
  }

  throw new FileSystemAccessError(e.message, e);
}

if (needsTransition) {
  const usedWidths = columnWidths.slice(0, currentCellCount);
  const collapsingWidths = columnWidths.slice(currentCellCount);
  return (
    "╟" +
    renderRuleSegment(usedWidths, "─", "┼") +
    "┼" +
    renderRuleSegment(collapsingWidths, "─", "┴") +
    "╢"
  );
} else if (currentCellCount === columnWidths.length) {
  return renderHorizontalRule("╟", columnWidths, "─", innerJoiner, "╢");
} else {
  const usedWidths = columnWidths.slice(0, currentCellCount);
  const remainingWidth = getUnusedColumnsWidth(
    columnWidths,
    currentCellCount,
  );
  return (
    "╟" +
    renderRuleSegment(usedWidths, "─", innerJoiner) +
    innerJoiner +
    "─".repeat(remainingWidth + 2) +
    "╢"
  );
}

class BlockscoutVerificationResponse implements VerificationResponse {
  public readonly status: number;
  public readonly message: string;

  constructor(response: BlockscoutResponse) {
    this.status = Number(response.status);
    this.message = response.result;
  }

  public isBytecodeMissingInNetworkError(): boolean {
    return this.message.startsWith("Unable to locate ContractCode at");
  }

  public isAlreadyVerified(): boolean {
    return this.message.startsWith("Smart-contract already verified.");
  }

  public addressIsNotAContract(): boolean {
    return this.message.startsWith("The address is not a smart contract");
  }

  public isOk(): boolean {
    return this.status === 1;
  }
}

for (const [sourceName, userLibAddresses] of Object.entries(userLibraries)) {
  for (const [userLibName, userLibAddress] of Object.entries(
    userLibAddresses,
  )) {
    if (
      sourceName in detectedLibraries &&
      userLibName in detectedLibraries[sourceName]
    ) {
      const detectedLibAddress = detectedLibraries[sourceName][userLibName];
      // detectedLibAddress may not always be lowercase due to extraction logic
      if (userLibAddress.toLowerCase() !== detectedLibAddress.toLowerCase()) {
        conflicts.push({
          library: `${sourceName}:${userLibName}`,
          detectedAddress: detectedLibAddress,
          userAddress: userLibAddress,
        });
      }
    }
  }
}

try {
  const moduleUrl = pathToFileURL(moduleAbsolutePath).href;
  const importedModule: Record<string, unknown> = await import(moduleUrl);

  return importedModule;
} catch (error) {
  ensureError(error);

  if ("code" in error && error.code === "ERR_MODULE_NOT_FOUND") {
    throw new HardhatError(
      HardhatError.ERRORS.HARDHAT_VERIFY.VALIDATION.MODULE_NOT_FOUND,
      { modulePath },
    );
  }

  if (error instanceof SyntaxError) {
    throw new HardhatError(
      HardhatError.ERRORS.HARDHAT_VERIFY.VALIDATION.MODULE_SYNTAX_ERROR,
      { modulePath, errorMessage: error.message },
    );
  }

  throw new HardhatError(
    HardhatError.ERRORS.HARDHAT_VERIFY.VALIDATION.IMPORT_MODULE_FAILED,
    { modulePath, errorMessage: error.message },
  );
}

