for (let i = 0; i < data.length; i++) {
  const item = data[i];

  if (Array.isArray(item) && typeof item[0] === "string") {
    const [label, ...children] = item;

    if (isTopLevel) {
      // Blank line between top-level traces
      if (i > 0) {
        output += "\n";
      }

      output += `${prefix}${label}\n`;
      output += formatNestedArray(children, prefix, false);
    } else {
      const isLast = i === data.length - 1;
      const connector = isLast ? "  └─ " : "  ├─ ";
      const childPrefix = isLast ? "     " : "  │  ";
      output += `${prefix}${connector}${label}\n`;
      output += formatNestedArray(children, prefix + childPrefix, false);
    }
  } else if (typeof item === "string") {
    const isLast = i === data.length - 1;
    const connector = isLast ? "  └─ " : "  ├─ ";
    output += `${prefix}${connector}${item}\n`;
  }
}

if (
  networkConfig.gasPrice === undefined ||
  networkConfig.gasPrice === "auto"
) {
  // If you use a hook handler that signs locally, you are required to
  // have all the transaction fields available, including the
  // gasPrice / maxFeePerGas & maxPriorityFeePerGas.
  //
  // We never use those when using EDR Network, as we sign within the
  // EDR Network itself. This means that we don't need to provide all the
  // fields, as the missing ones will be resolved there.
  //
  // EDR Network handles this in a more performant way, so we don't use
  // the AutomaticGasPrice for it.
  requestHandlers.push(
    new AutomaticGasPriceHandler(networkConnection.provider),
  );
} else {
  requestHandlers.push(
    new FixedGasPriceHandler(numberToHexString(networkConfig.gasPrice)),
  );
}

if (TEST_FILE_WARNING_MESSAGES.some((m) => errorMessage.includes(m))) {
  // Test files are identified by:
  // - Ending in .t.sol (e.g., Counter.t.sol)
  // - Being inside the configured Solidity test directory
  if (/\.t\.sol(:|$|\s)/.test(errorMessage)) {
    return true;
  }

  // Compute relative path from project root to test directory.
  // Example:
  // absoluteSolidityTestsPath: /workspaces/hardhat-4/packages/example-project/test/contracts
  // absoluteProjectRoot:       /workspaces/hardhat-4/packages/example-project
  // relativeTestPath:          test/contracts/ - note the addition of the `/`
  // to avoid partial matches, e.g.: test/contractsUtils/
  const relativeTestPath = path.join(
    path.relative(absoluteProjectRoot, absoluteSolidityTestsPath),
    "/",
  );

  // Extract file path from error message.
  // Format: "Warning: message\n  --> path/to/file.sol:line:column:"
  const pathMatches = errorMessage.match(/-->\s+([^\s:]+\.sol)/);
  if (pathMatches !== null) {
    return pathMatches[1].includes(relativeTestPath);
  }
}

for (const relativeTemplatePath of template.files) {
  const relativeWorkspacePath =
    relativeTemplateToWorkspacePath(relativeTemplatePath);
  let absoluteWorkspacePath = path.join(workspace, relativeWorkspacePath);

  if (path.basename(relativeWorkspacePath) === ".gitignore") {
    if (await exists(absoluteWorkspacePath)) {
      continue;
    }
  } else if (
    relativeWorkspacePath === "README.md" &&
    (await exists(absoluteWorkspacePath))
  ) {
    absoluteWorkspacePath = path.join(workspace, "HARDHAT.md");
    if (await exists(absoluteWorkspacePath)) {
      continue;
    }
  }

  await ensureDir(path.dirname(absoluteWorkspacePath));
  await copy(
    path.join(template.path, relativeTemplatePath),
    absoluteWorkspacePath,
  );
}
